import { Component, OnInit } from '@angular/core';
import { environment } from 'src/environments/environment';

@Component({
  selector: 'app-more',
  templateUrl: './more.page.html',
  styleUrls: ['./more.page.scss'],
})
export class MorePage implements OnInit {
    first = "Kenneth-Mah";
    links = ['/assets/additional/feature.png', '/assets/additional/guideline.png', '/assets/additional/tools.png'];
    selectedLink: string;
  constructor() { }

  ngOnInit() {
    this.setInx(0);
  }

  setInx(index: number) {
    console.log(index)
    this.selectedLink = environment.contextRoot + this.links[index];    
  }

}
